(function () {
  var root = window;

  if (root.__flowdataPrefetchStarted) {
    return;
  }
  root.__flowdataPrefetchStarted = true;

  var store = (root.__flowdataPrefetch = root.__flowdataPrefetch || {});

  store.tryDispose = function () {
    var bucket = root.__flowdataPrefetch;
    if (!bucket) {
      return;
    }
    if (
      !bucket.scanPrefetchPromise &&
      !bucket.scanPrefetchKey &&
      !bucket.transPrefetchPromise &&
      !bucket.transPrefetchKey
    ) {
      try {
        delete root.__flowdataPrefetch;
      } catch (e) {
        root.__flowdataPrefetch = {};
      }
    }
  };

  store.takeScanPrefetchIfKey = function (key) {
    var bucket = root.__flowdataPrefetch;
    if (
